mapper.select:
select *
from item

    where category = #{category}


    order by ${sortBy}

mapper.update:
UPDATE item
SET stock = stock - #{quantity},
    update_time = NOW()
WHERE id = #{itemId}
  AND stock >= #{quantity}
  AND status = 1

mapper.select:
select *
from item


        and name like concat('%', #{name}, '%')


        and category = #{category}


        and status = #{status}


order by create_time desc
